import math
from typing import List, Dict, Tuple

# Helper real comparison using six significant digits relative tolerance.
def realcompare(a: float, b: float) -> str:
    # Relative comparison to six significant digits. Scale protects small numbers.
    scale = max(abs(a), abs(b), 1.0)
    diff = abs(a - b)
    if diff <= scale * 1e-6:
        return "EQ"
    return "LT" if a < b else "GT"


def _distance(p1: Tuple[float, float], p2: Tuple[float, float]) -> float:
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def _triangle_area(p1: Tuple[float, float], p2: Tuple[float, float], p3: Tuple[float, float]) -> float:
    return abs((p1[0] * (p2[1] - p3[1]) + p2[0] * (p3[1] - p1[1]) + p3[0] * (p1[1] - p2[1])) / 2.0)


def _angle(p1: Tuple[float, float], vertex: Tuple[float, float], p3: Tuple[float, float]) -> float:
    v1 = (p1[0] - vertex[0], p1[1] - vertex[1])
    v2 = (p3[0] - vertex[0], p3[1] - vertex[1])
    dot = v1[0] * v2[0] + v1[1] * v2[1]
    norm1 = math.hypot(*v1)
    norm2 = math.hypot(*v2)
    if norm1 == 0 or norm2 == 0:
        return None  # undefined
    cos_theta = dot / (norm1 * norm2)
    cos_theta = max(min(cos_theta, 1.0), -1.0)
    return math.acos(cos_theta)


def _points_in_circle_within_radius(p1: Tuple[float, float], p2: Tuple[float, float], p3: Tuple[float, float], radius: float) -> bool:
    # Small helper to check if three points can be contained in or on circle with given radius.
    # Degenerate cases handled explicitly.
    d12 = _distance(p1, p2)
    d13 = _distance(p1, p3)
    d23 = _distance(p2, p3)
    max_d = max(d12, d13, d23)
    # If any pair farther than 2*radius, impossible.
    if realcompare(max_d, 2 * radius) == "GT":
        return False
    # Colinear case: radius must be at least half of max distance.
    area = _triangle_area(p1, p2, p3)
    if realcompare(area, 0.0) == "EQ":
        return realcompare(max_d / 2.0, radius) != "GT"
    # General case: compute circumradius and compare.
    circumradius = (d12 * d13 * d23) / (4.0 * area)
    return realcompare(circumradius, radius) != "GT"


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, float],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    points = list(zip(x, y))
    PI = 3.1415926535

    cmv = [False] * 15

    # LIC 1
    length1 = parameters["LENGTH1"]
    for i in range(numpoints - 1):
        if realcompare(_distance(points[i], points[i + 1]), length1) == "GT":
            cmv[0] = True
            break

    # LIC 2
    radius1 = parameters["RADIUS1"]
    for i in range(numpoints - 2):
        if not _points_in_circle_within_radius(points[i], points[i + 1], points[i + 2], radius1):
            cmv[1] = True
            break

    # LIC 3
    epsilon = parameters["EPSILON"]
    for i in range(numpoints - 2):
        angle = _angle(points[i], points[i + 1], points[i + 2])
        if angle is None:
            continue
        if realcompare(angle, PI - epsilon) == "LT" or realcompare(angle, PI + epsilon) == "GT":
            cmv[2] = True
            break

    # LIC 4
    area1 = parameters["AREA1"]
    for i in range(numpoints - 2):
        if realcompare(_triangle_area(points[i], points[i + 1], points[i + 2]), area1) == "GT":
            cmv[3] = True
            break

    # LIC 5
    q_pts = parameters["Q_PTS"]
    quads = parameters["QUADS"]
    if q_pts >= 2 and q_pts <= numpoints:
        def quadrant(pt: Tuple[float, float]) -> int:
            x0, y0 = pt
            x_cmp = realcompare(x0, 0.0)
            y_cmp = realcompare(y0, 0.0)
            if x_cmp != "LT" and y_cmp != "LT":
                return 1
            if x_cmp == "LT" and y_cmp != "LT":
                return 2
            if x_cmp != "GT" and y_cmp == "LT":
                return 3
            return 4

        for i in range(numpoints - q_pts + 1):
            seen = set()
            for j in range(q_pts):
                seen.add(quadrant(points[i + j]))
            if len(seen) > quads:
                cmv[4] = True
                break

    # LIC 6
    for i in range(numpoints - 1):
        if realcompare(points[i + 1][0] - points[i][0], 0.0) == "LT":
            cmv[5] = True
            break

    # LIC 7
    dist = parameters["DIST"]
    n_pts = parameters["N_PTS"]
    if numpoints >= 3 and n_pts >= 3:
        for i in range(numpoints - n_pts + 1):
            start = points[i]
            end = points[i + n_pts - 1]
            line_dx = end[0] - start[0]
            line_dy = end[1] - start[1]
            line_len = math.hypot(line_dx, line_dy)
            for j in range(i, i + n_pts):
                if realcompare(line_len, 0.0) == "EQ":
                    d = _distance(points[j], start)
                else:
                    num = abs(line_dy * points[j][0] - line_dx * points[j][1] + end[0] * start[1] - end[1] * start[0])
                    d = num / line_len
                if realcompare(d, dist) == "GT":
                    cmv[6] = True
                    break
            if cmv[6]:
                break

    # LIC 8
    k_pts = parameters["K_PTS"]
    if numpoints >= 3:
        for i in range(numpoints - k_pts - 1):
            if realcompare(_distance(points[i], points[i + k_pts + 1]), length1) == "GT":
                cmv[7] = True
                break

    # LIC 9
    a_pts = parameters["A_PTS"]
    b_pts = parameters["B_PTS"]
    if numpoints >= 5:
        for i in range(numpoints - (a_pts + b_pts) - 2):
            p1 = points[i]
            p2 = points[i + a_pts + 1]
            p3 = points[i + a_pts + b_pts + 2]
            if not _points_in_circle_within_radius(p1, p2, p3, radius1):
                cmv[8] = True
                break

    # LIC 10
    c_pts = parameters["C_PTS"]
    d_pts = parameters["D_PTS"]
    if numpoints >= 5:
        for i in range(numpoints - (c_pts + d_pts) - 2):
            p1 = points[i]
            vertex = points[i + c_pts + 1]
            p3 = points[i + c_pts + d_pts + 2]
            angle = _angle(p1, vertex, p3)
            if angle is None:
                continue
            if realcompare(angle, PI - epsilon) == "LT" or realcompare(angle, PI + epsilon) == "GT":
                cmv[9] = True
                break

    # LIC 11
    e_pts = parameters["E_PTS"]
    f_pts = parameters["F_PTS"]
    if numpoints >= 5:
        for i in range(numpoints - (e_pts + f_pts) - 2):
            p1 = points[i]
            p2 = points[i + e_pts + 1]
            p3 = points[i + e_pts + f_pts + 2]
            if realcompare(_triangle_area(p1, p2, p3), area1) == "GT":
                cmv[10] = True
                break

    # LIC 12
    g_pts = parameters["G_PTS"]
    if numpoints >= 3:
        for i in range(numpoints - g_pts - 1):
            if realcompare(points[i + g_pts + 1][0] - points[i][0], 0.0) == "LT":
                cmv[11] = True
                break

    # LIC 13
    length2 = parameters["LENGTH2"]
    if numpoints >= 3:
        found_gt = False
        found_lt = False
        for i in range(numpoints - k_pts - 1):
            d = _distance(points[i], points[i + k_pts + 1])
            if not found_gt and realcompare(d, length1) == "GT":
                found_gt = True
            if not found_lt and realcompare(d, length2) == "LT":
                found_lt = True
            if found_gt and found_lt:
                cmv[12] = True
                break

    # LIC 14
    radius2 = parameters["RADIUS2"]
    if numpoints >= 5:
        found_gt = False
        found_le = False
        for i in range(numpoints - (a_pts + b_pts) - 2):
            p1 = points[i]
            p2 = points[i + a_pts + 1]
            p3 = points[i + a_pts + b_pts + 2]
            if not found_gt and not _points_in_circle_within_radius(p1, p2, p3, radius1):
                found_gt = True
            if not found_le and _points_in_circle_within_radius(p1, p2, p3, radius2):
                found_le = True
            if found_gt and found_le:
                cmv[13] = True
                break

    # LIC 15
    area2 = parameters["AREA2"]
    if numpoints >= 5:
        found_gt = False
        found_lt = False
        for i in range(numpoints - (e_pts + f_pts) - 2):
            p1 = points[i]
            p2 = points[i + e_pts + 1]
            p3 = points[i + e_pts + f_pts + 2]
            area_val = _triangle_area(p1, p2, p3)
            if not found_gt and realcompare(area_val, area1) == "GT":
                found_gt = True
            if not found_lt and realcompare(area_val, area2) == "LT":
                found_lt = True
            if found_gt and found_lt:
                cmv[14] = True
                break

    # PUM construction
    pum = [[False for _ in range(15)] for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = bool(pum_diag[i])
            else:
                connector = lcm[i][j]
                if connector == "NOTUSED":
                    pum[i][j] = True
                elif connector == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif connector == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]
                else:
                    raise ValueError("Invalid connector value")

    # FUV
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            if all(pum[i][j] for j in range(15)):
                fuv[i] = True
            else:
                fuv[i] = False

    launch = all(fuv)
    return cmv, pum, fuv, launch
